@import "tailwindcss";

@theme inline {
  --font-sans: var(--font-syne);
  --font-mono: var(--font-dm-mono);
}

:root {
  --bg: #07090f;
  --bg-card: #0d1117;
  --bg-card-hover: #111827;
  --bg-panel: #0a0d14;
  --border: rgba(255, 255, 255, 0.06);
  --border-strong: rgba(255, 255, 255, 0.12);
  --accent: #f97316;
  --accent-dim: rgba(249, 115, 22, 0.15);
  --accent-glow: rgba(249, 115, 22, 0.35);
  --blue: #3b82f6;
  --blue-dim: rgba(59, 130, 246, 0.15);
  --green: #10b981;
  --text-primary: #f1f5f9;
  --text-secondary: #94a3b8;
  --text-muted: #475569;
  --rank-1: #f97316;
  --rank-2: #94a3b8;
  --rank-3: #fbbf24;
}

* {
  box-sizing: border-box;
}

html,
body {
  height: 100%;
  overflow: hidden;
}

body {
  background: var(--bg);
  color: var(--text-primary);
  font-family: var(--font-syne), system-ui, sans-serif;
  -webkit-font-smoothing: antialiased;
}

/* ── Scrollbar ─────────────────────────────────────────────── */
::-webkit-scrollbar {
  width: 3px;
  height: 3px;
}
::-webkit-scrollbar-track {
  background: transparent;
}
::-webkit-scrollbar-thumb {
  background: rgba(255, 255, 255, 0.1);
  border-radius: 2px;
}
::-webkit-scrollbar-thumb:hover {
  background: rgba(255, 255, 255, 0.2);
}

/* ── Background grid ──────────────────────────────────────── */
.bg-grid {
  background-image: linear-gradient(rgba(255, 255, 255, 0.015) 1px, transparent 1px),
    linear-gradient(90deg, rgba(255, 255, 255, 0.015) 1px, transparent 1px);
  background-size: 40px 40px;
}

/* ── Score bar fill animation ─────────────────────────────── */
.score-fill {
  transition: width 0.6s cubic-bezier(0.4, 0, 0.2, 1);
}

/* ── Rank glow ─────────────────────────────────────────────── */
.rank-1-glow {
  box-shadow: 0 0 0 1px rgba(249, 115, 22, 0.3), 0 0 16px rgba(249, 115, 22, 0.25);
}

/* ── Card hover ──────────────────────────────────────────── */
.engineer-card {
  transition: background 0.15s ease, border-color 0.15s ease;
}
.engineer-card:hover {
  background: var(--bg-card-hover);
}

/* ── Table row hover ─────────────────────────────────────── */
.table-row {
  transition: background 0.1s ease;
}
.table-row:hover {
  background: rgba(255, 255, 255, 0.03);
}
.table-row.selected {
  background: rgba(249, 115, 22, 0.08);
}

/* ── Collapsible methodology ─────────────────────────────── */
.methodology-panel {
  overflow: hidden;
  transition: max-height 0.3s cubic-bezier(0.4, 0, 0.2, 1),
    opacity 0.25s ease;
}
.methodology-panel.open {
  max-height: 120px;
  opacity: 1;
}
.methodology-panel.closed {
  max-height: 0;
  opacity: 0;
}

/* ── Graph overlay ───────────────────────────────────────── */
.node-overlay {
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
  background: rgba(10, 13, 20, 0.88);
  border: 1px solid rgba(249, 115, 22, 0.25);
}

