"use client";

import { useMemo } from "react";
import Image from "next/image";
import { Engineer } from "../types";

/* ── Tiny horizontal bar ────────────────────────────────── */
function MiniBar({ value, color, width = 48 }: { value: number; color: string; width?: number }) {
  return (
    <div
      className="rounded-full overflow-hidden"
      style={{ width, height: 3, background: "rgba(255,255,255,0.06)" }}
    >
      <div
        className="h-full rounded-full score-fill"
        style={{ width: `${Math.round(value * 100)}%`, background: color }}
      />
    </div>
  );
}

/* ── DORA metric row (shows the sub-metric + its weight) ── */
function DoraRow({
  label,
  value,
  weight,
  color,
  detail,
}: {
  label: string;
  value: number;
  weight: string;
  color: string;
  detail: string;
}) {
  return (
    <div className="flex items-center gap-2">
      <span
        className="w-[72px] text-[9px] shrink-0"
        style={{ color: "var(--text-muted)", fontFamily: "var(--font-dm-mono)" }}
      >
        {label}{" "}
        <span style={{ opacity: 0.5 }}>({weight})</span>
      </span>
      <div
        className="flex-1 rounded-full overflow-hidden"
        style={{ height: 3, background: "rgba(255,255,255,0.06)" }}
      >
        <div
          className="h-full rounded-full score-fill"
          style={{ width: `${Math.round(value * 100)}%`, background: color }}
        />
      </div>
      <span
        className="w-7 text-right text-[10px] font-medium shrink-0"
        style={{ color, fontFamily: "var(--font-dm-mono)" }}
      >
        {(value * 100).toFixed(0)}
      </span>
    </div>
  );
}

/* ── Rank badge ──────────────────────────────────────────── */
function RankBadge({ rank }: { rank: number }) {
  const colors: Record<number, { bg: string; fg: string; glow?: string }> = {
    1: { bg: "var(--accent)", fg: "#fff", glow: "0 0 12px rgba(249,115,22,0.5)" },
    2: { bg: "rgba(192,192,192,0.18)", fg: "#c0c0c0" },
    3: { bg: "rgba(251,191,36,0.15)", fg: "#fbbf24" },
    4: { bg: "rgba(71,85,105,0.2)", fg: "#64748b" },
    5: { bg: "rgba(71,85,105,0.2)", fg: "#64748b" },
  };
  const c = colors[rank];
  return (
    <div
      className="w-7 h-7 rounded-full flex items-center justify-center text-xs font-bold shrink-0"
      style={{ background: c.bg, color: c.fg, boxShadow: c.glow, fontFamily: "var(--font-dm-mono)" }}
    >
      {rank}
    </div>
  );
}

/* ── Engineer card (top 5) ──────────────────────────────── */
function EngineerCard({
  engineer,
  rank,
  selected,
  onClick,
}: {
  engineer: Engineer;
  rank: number;
  selected: boolean;
  onClick: () => void;
}) {
  const d = engineer.dora;
  const borderColor =
    rank === 1 ? "rgba(249,115,22,0.4)" : rank === 2 ? "rgba(192,192,192,0.2)" : rank === 3 ? "rgba(251,191,36,0.2)" : "rgba(255,255,255,0.05)";

  // Compute contribution amounts for the formula display
  const doraContrib = (engineer.doraScore * 0.6 * 100).toFixed(1);
  const prContrib = (engineer.pageRankScore * 0.4 * 100).toFixed(1);

  return (
    <button
      onClick={onClick}
      className="engineer-card w-full text-left rounded-lg border"
      style={{
        borderColor: selected ? "rgba(249,115,22,0.5)" : borderColor,
        background: selected ? "rgba(249,115,22,0.06)" : rank === 1 ? "rgba(249,115,22,0.04)" : "var(--bg-card)",
        outline: "none",
        padding: "10px 12px",
      }}
    >
      {/* Row 1: identity + impact score */}
      <div className="flex items-center gap-2.5 mb-2">
        <RankBadge rank={rank} />
        <Image
          src={engineer.avatar_url}
          alt={engineer.login}
          width={28}
          height={28}
          className="rounded-full shrink-0"
          style={{ border: rank === 1 ? "2px solid rgba(249,115,22,0.4)" : "1px solid rgba(255,255,255,0.1)" }}
        />
        <div className="flex-1 min-w-0">
          <div className="text-sm font-semibold text-white leading-none truncate" style={{ fontFamily: "var(--font-syne)" }}>
            {engineer.login}
          </div>
          <div className="text-[10px] mt-0.5" style={{ color: "var(--text-muted)", fontFamily: "var(--font-dm-mono)" }}>
            {engineer.prsMerged} PRs merged · {engineer.reviewsGiven} reviews given
          </div>
        </div>
        <div className="text-right shrink-0">
          <div
            className="text-lg font-bold leading-none"
            style={{ color: rank === 1 ? "var(--accent)" : "var(--text-primary)", fontFamily: "var(--font-dm-mono)" }}
          >
            {(engineer.impactScore * 100).toFixed(1)}
          </div>
          <div className="text-[8px] uppercase tracking-wider" style={{ color: "var(--text-muted)" }}>
            impact
          </div>
        </div>
      </div>

      {/* Row 2: The formula — showing how impact was computed */}
      <div
        className="rounded-md px-2.5 py-1.5 mb-2 flex items-center gap-1.5 text-[10px]"
        style={{
          background: "rgba(255,255,255,0.02)",
          border: "1px solid rgba(255,255,255,0.04)",
          fontFamily: "var(--font-dm-mono)",
        }}
      >
        <span style={{ color: "var(--text-muted)" }}>Impact =</span>
        <span style={{ color: "var(--green)" }}>{(engineer.doraScore * 100).toFixed(0)}</span>
        <span style={{ color: "var(--text-muted)", opacity: 0.5 }}>×0.6</span>
        <span style={{ color: "var(--text-muted)" }}>+</span>
        <span style={{ color: "var(--blue)" }}>{(engineer.pageRankScore * 100).toFixed(0)}</span>
        <span style={{ color: "var(--text-muted)", opacity: 0.5 }}>×0.4</span>
        <span style={{ color: "var(--text-muted)" }}>=</span>
        <span style={{ color: "var(--accent)", fontWeight: 600 }}>
          {doraContrib}
        </span>
        <span style={{ color: "var(--text-muted)" }}>+</span>
        <span style={{ color: "var(--accent)", fontWeight: 600 }}>
          {prContrib}
        </span>
        <span style={{ color: "var(--text-muted)" }}>=</span>
        <span className="font-bold" style={{ color: "var(--accent)" }}>
          {(engineer.impactScore * 100).toFixed(1)}
        </span>
      </div>

      {/* Row 3: DORA sub-metrics breakdown */}
      <div className="flex flex-col gap-0.5">
        <DoraRow label="Merge freq" value={d.mergeFrequency} weight="30%" color="#10b981" detail={`${engineer.prsMerged} PRs`} />
        <DoraRow label="Lead time" value={d.leadTime} weight="25%" color="#06b6d4" detail="lower is better" />
        <DoraRow label="Fail rate" value={d.changeFailureRate} weight="25%" color="#8b5cf6" detail="inverted" />
        <DoraRow label="Recency" value={d.recencyScore} weight="20%" color="#f59e0b" detail="0.85/wk decay" />
      </div>

      {/* Row 4: Summary */}
      {engineer.summary && (
        <p
          className="text-[9px] leading-relaxed mt-2 pt-2 line-clamp-2"
          style={{ color: "var(--text-muted)", borderTop: "1px solid rgba(255,255,255,0.04)", fontFamily: "var(--font-dm-mono)" }}
        >
          {engineer.summary}
        </p>
      )}
    </button>
  );
}

/* ── Main panel ──────────────────────────────────────────── */
interface Props {
  engineers: Engineer[];
  selectedLogin: string | null;
  onSelectLogin: (login: string | null) => void;
}

export default function LeaderboardPanel({ engineers, selectedLogin, onSelectLogin }: Props) {
  const top5 = engineers.slice(0, 5);

  return (
    <div
      className="flex flex-col border-r overflow-y-auto"
      style={{ width: "480px", flexShrink: 0, borderColor: "var(--border)", background: "var(--bg-panel)" }}
    >
      {/* Section header */}
      <div className="flex-none px-4 pt-3 pb-2">
        <div className="flex items-center justify-between mb-1">
          <span
            className="text-[10px] uppercase tracking-widest font-semibold"
            style={{ color: "var(--text-muted)", fontFamily: "var(--font-dm-mono)" }}
          >
            Top 5 Engineers by Impact
          </span>
        </div>
        <p
          className="text-[10px] leading-relaxed"
          style={{ color: "var(--text-muted)", fontFamily: "var(--font-dm-mono)" }}
        >
          Each card shows the full calculation. Click any engineer to see their review network in the graph.
        </p>
      </div>

      {/* Cards */}
      <div className="flex-1 px-3 pb-3 overflow-y-auto">
        <div className="flex flex-col gap-2">
          {top5.map((eng, i) => (
            <EngineerCard
              key={eng.login}
              engineer={eng}
              rank={i + 1}
              selected={selectedLogin === eng.login}
              onClick={() => onSelectLogin(selectedLogin === eng.login ? null : eng.login)}
            />
          ))}
        </div>
      </div>
    </div>
  );
}

