"use client";

import { useState, useMemo, useRef, useEffect } from "react";
import Image from "next/image";
import { ChevronUp, ChevronDown, Trophy, GitPullRequest, Eye } from "lucide-react";
import { Engineer } from "../types";

/* ── Score bar ──────────────────────────────────────────────── */
function ScoreBar({
  label,
  value,
  color,
  compact,
}: {
  label: string;
  value: number;
  color: string;
  compact?: boolean;
}) {
  const pct = Math.round(value * 100);
  return (
    <div className="flex items-center gap-2">
      <span
        className={`${compact ? "w-11" : "w-14"} text-[9px] uppercase tracking-wider shrink-0`}
        style={{ color: "var(--text-muted)", fontFamily: "var(--font-dm-mono)" }}
      >
        {label}
      </span>
      <div
        className="flex-1 rounded-full overflow-hidden"
        style={{ height: compact ? "2px" : "3px", background: "rgba(255,255,255,0.06)" }}
      >
        <div
          className="h-full rounded-full score-fill"
          style={{ width: `${pct}%`, background: color }}
        />
      </div>
      <span
        className="w-6 text-right text-[10px]"
        style={{ color: "var(--text-secondary)", fontFamily: "var(--font-dm-mono)" }}
      >
        {pct}
      </span>
    </div>
  );
}

/* ── Sparkline ────────────────────────────────────────────── */
function Sparkline({ data }: { data: { week: string; prCount: number }[] }) {
  const max = Math.max(...data.map((d) => d.prCount), 1);
  const W = 48;
  const H = 16;
  const step = W / (data.length - 1 || 1);

  const points = data
    .map((d, i) => `${i * step},${H - (d.prCount / max) * H}`)
    .join(" ");

  const area =
    `M 0,${H} ` +
    data
      .map((d, i) => `L ${i * step},${H - (d.prCount / max) * H}`)
      .join(" ") +
    ` L ${W},${H} Z`;

  return (
    <svg width={W} height={H} style={{ overflow: "visible", flexShrink: 0 }}>
      <defs>
        <linearGradient id="sparkGrad" x1="0" y1="0" x2="0" y2="1">
          <stop offset="0%" stopColor="var(--accent)" stopOpacity={0.3} />
          <stop offset="100%" stopColor="var(--accent)" stopOpacity={0} />
        </linearGradient>
      </defs>
      <path d={area} fill="url(#sparkGrad)" />
      <polyline
        points={points}
        fill="none"
        stroke="var(--accent)"
        strokeWidth="1.5"
        strokeLinejoin="round"
        strokeLinecap="round"
        opacity={0.7}
      />
    </svg>
  );
}

/* ── Rank badge ───────────────────────────────────────────── */
function RankBadge({ rank }: { rank: number }) {
  const configs: Record<number, { bg: string; color: string; shadow?: string; emoji?: string }> = {
    1: { bg: "var(--accent)", color: "#fff", shadow: "0 0 12px rgba(249,115,22,0.5)", emoji: "🥇" },
    2: { bg: "rgba(192,192,192,0.18)", color: "#c0c0c0", emoji: "🥈" },
    3: { bg: "rgba(251,191,36,0.15)", color: "#fbbf24", emoji: "🥉" },
    4: { bg: "rgba(71,85,105,0.2)", color: "#64748b" },
    5: { bg: "rgba(71,85,105,0.2)", color: "#64748b" },
  };
  const s = configs[rank];
  return (
    <div
      className="w-7 h-7 rounded-full flex items-center justify-center text-xs font-bold shrink-0"
      style={{
        background: s.bg,
        color: s.color,
        boxShadow: s.shadow,
        fontFamily: "var(--font-dm-mono)",
      }}
    >
      {rank}
    </div>
  );
}

/* ── DORA Breakdown mini bars (for expanded card) ────────── */
function DoraBreakdown({ dora }: { dora: Engineer["dora"] }) {
  const items = [
    { label: "Merge freq", value: dora.mergeFrequency, color: "#10b981" },
    { label: "Lead time", value: dora.leadTime, color: "#06b6d4" },
    { label: "Fail rate", value: dora.changeFailureRate, color: "#8b5cf6" },
    { label: "Recency", value: dora.recencyScore, color: "#f59e0b" },
  ];
  return (
    <div className="grid grid-cols-4 gap-2">
      {items.map(({ label, value, color }) => (
        <div key={label} className="text-center">
          <div
            className="text-[10px] font-bold"
            style={{ color, fontFamily: "var(--font-dm-mono)" }}
          >
            {(value * 100).toFixed(0)}
          </div>
          <div
            className="text-[8px] uppercase tracking-wider"
            style={{ color: "var(--text-muted)", fontFamily: "var(--font-dm-mono)" }}
          >
            {label}
          </div>
        </div>
      ))}
    </div>
  );
}

/* ── Engineer card (top 5) ──────────────────────────────────── */
function EngineerCard({
  engineer,
  rank,
  selected,
  expanded,
  onClick,
}: {
  engineer: Engineer;
  rank: number;
  selected: boolean;
  expanded: boolean;
  onClick: () => void;
}) {
  const borderColor =
    rank === 1
      ? "rgba(249,115,22,0.4)"
      : rank === 2
      ? "rgba(192,192,192,0.2)"
      : rank === 3
      ? "rgba(251,191,36,0.2)"
      : "rgba(255,255,255,0.05)";

  return (
    <button
      onClick={onClick}
      className="engineer-card w-full text-left rounded-lg border transition-all"
      style={{
        borderColor: selected ? "rgba(249,115,22,0.5)" : borderColor,
        background: selected
          ? "rgba(249,115,22,0.06)"
          : rank === 1
          ? "rgba(249,115,22,0.04)"
          : "var(--bg-card)",
        outline: "none",
        padding: expanded ? "12px" : "8px 12px",
      }}
    >
      {/* Top row: rank + avatar + name + sparkline + impact */}
      <div className="flex items-center gap-2.5">
        <RankBadge rank={rank} />
        <Image
          src={engineer.avatar_url}
          alt={engineer.login}
          width={expanded ? 32 : 26}
          height={expanded ? 32 : 26}
          className="rounded-full shrink-0"
          style={{
            border: rank === 1 ? "2px solid rgba(249,115,22,0.4)" : "1px solid rgba(255,255,255,0.1)",
          }}
        />
        <div className="flex-1 min-w-0">
          <div
            className="text-sm font-semibold text-white leading-none truncate"
            style={{ fontFamily: "var(--font-syne)" }}
          >
            {engineer.login}
          </div>
          <div
            className="flex items-center gap-2 text-[10px] mt-0.5"
            style={{ color: "var(--text-muted)", fontFamily: "var(--font-dm-mono)" }}
          >
            <span className="flex items-center gap-0.5">
              <GitPullRequest size={9} />
              {engineer.prsMerged}
            </span>
            <span className="flex items-center gap-0.5">
              <Eye size={9} />
              {engineer.reviewsGiven}
            </span>
          </div>
        </div>
        <Sparkline data={engineer.weeklyActivity} />
        <div className="text-right shrink-0 pl-1">
          <div
            className="text-lg font-bold leading-none"
            style={{
              color: rank === 1 ? "var(--accent)" : "var(--text-primary)",
              fontFamily: "var(--font-dm-mono)",
            }}
          >
            {(engineer.impactScore * 100).toFixed(1)}
          </div>
          <div
            className="text-[8px] uppercase tracking-wider"
            style={{ color: "var(--text-muted)" }}
          >
            impact
          </div>
        </div>
      </div>

      {/* Expanded details */}
      {expanded && (
        <div className="mt-2.5 pt-2.5" style={{ borderTop: "1px solid rgba(255,255,255,0.06)" }}>
          {/* Summary */}
          {engineer.summary && (
            <p
              className="text-[10px] leading-relaxed mb-2.5"
              style={{
                color: "var(--text-secondary)",
                fontFamily: "var(--font-dm-mono)",
              }}
            >
              {engineer.summary}
            </p>
          )}

          {/* Score bars */}
          <div className="flex flex-col gap-1 mb-2.5">
            <ScoreBar label="DORA" value={engineer.doraScore} color="var(--green)" compact />
            <ScoreBar label="PageRank" value={engineer.pageRankScore} color="var(--blue)" compact />
            <ScoreBar label="Impact" value={engineer.impactScore} color="var(--accent)" compact />
          </div>

          {/* DORA breakdown */}
          <div
            className="rounded-md p-2"
            style={{ background: "rgba(255,255,255,0.02)", border: "1px solid rgba(255,255,255,0.04)" }}
          >
            <div
              className="text-[8px] uppercase tracking-widest mb-1.5"
              style={{ color: "var(--text-muted)", fontFamily: "var(--font-dm-mono)" }}
            >
              DORA Breakdown
            </div>
            <DoraBreakdown dora={engineer.dora} />
          </div>
        </div>
      )}
    </button>
  );
}

/* ── Sort types ─────────────────────────────────────────────── */
type SortKey = "rank" | "impactScore" | "doraScore" | "pageRankScore" | "prsAuthored";
type SortDir = "asc" | "desc";

/* ── Main panel ─────────────────────────────────────────────── */
interface Props {
  engineers: Engineer[];
  selectedLogin: string | null;
  onSelectLogin: (login: string | null) => void;
}

export default function LeaderboardPanel({
  engineers,
  selectedLogin,
  onSelectLogin,
}: Props) {
  const [sortKey, setSortKey] = useState<SortKey>("impactScore");
  const [sortDir, setSortDir] = useState<SortDir>("desc");
  const [expandedCard, setExpandedCard] = useState<string | null>(null);
  const top5ScrollRef = useRef<HTMLDivElement>(null);

  const top5 = engineers.slice(0, 5);

  const sortedAll = useMemo(() => {
    const ranked = engineers.map((e, i) => ({ ...e, rank: i + 1 }));
    return [...ranked].sort((a, b) => {
      let av: number, bv: number;
      if (sortKey === "rank") {
        av = a.rank;
        bv = b.rank;
      } else if (sortKey === "prsAuthored") {
        av = a.prsAuthored;
        bv = b.prsAuthored;
      } else {
        av = a[sortKey];
        bv = b[sortKey];
      }
      return sortDir === "desc" ? bv - av : av - bv;
    });
  }, [engineers, sortKey, sortDir]);

  function handleSort(key: SortKey) {
    if (key === sortKey) {
      setSortDir((d) => (d === "desc" ? "asc" : "desc"));
    } else {
      setSortKey(key);
      setSortDir("desc");
    }
  }

  function handleCardClick(login: string) {
    // Toggle expand
    if (expandedCard === login) {
      setExpandedCard(null);
    } else {
      setExpandedCard(login);
    }
    // Always select on graph
    onSelectLogin(selectedLogin === login ? null : login);
  }

  function SortIcon({ col }: { col: SortKey }) {
    if (sortKey !== col)
      return (
        <span style={{ color: "var(--text-muted)", opacity: 0.4 }}>
          <ChevronDown size={10} />
        </span>
      );
    return sortDir === "desc" ? (
      <ChevronDown size={10} style={{ color: "var(--accent)" }} />
    ) : (
      <ChevronUp size={10} style={{ color: "var(--accent)" }} />
    );
  }

  const colBtn =
    "flex items-center gap-0.5 hover:text-white transition-colors cursor-pointer select-none";

  return (
    <div
      className="flex flex-col border-r"
      style={{
        width: "480px",
        flexShrink: 0,
        borderColor: "var(--border)",
        background: "var(--bg-panel)",
      }}
    >
      {/* ── Top 5 section — scrollable ────────────────── */}
      <div
        className="flex flex-col min-h-0"
        style={{ maxHeight: "55%", borderBottom: "1px solid var(--border)" }}
      >
        <div className="flex-none flex items-center justify-between px-3 pt-3 pb-1.5">
          <div className="flex items-center gap-2">
            <Trophy size={12} style={{ color: "var(--accent)" }} />
            <span
              className="text-[10px] uppercase tracking-widest font-semibold"
              style={{ color: "var(--text-muted)", fontFamily: "var(--font-dm-mono)" }}
            >
              Top Performers
            </span>
          </div>
          <span
            className="text-[10px]"
            style={{ color: "var(--text-muted)", fontFamily: "var(--font-dm-mono)" }}
          >
            click to expand
          </span>
        </div>
        <div
          ref={top5ScrollRef}
          className="flex-1 overflow-y-auto px-3 pb-2"
        >
          <div className="flex flex-col gap-1.5">
            {top5.map((eng, i) => (
              <EngineerCard
                key={eng.login}
                engineer={eng}
                rank={i + 1}
                selected={selectedLogin === eng.login}
                expanded={expandedCard === eng.login}
                onClick={() => handleCardClick(eng.login)}
              />
            ))}
          </div>
        </div>
      </div>

      {/* ── Full table section ──────────────────────────── */}
      <div className="flex flex-col flex-1 min-h-0">
        <div
          className="flex-none px-3 py-2 flex items-center justify-between"
          style={{ borderBottom: "1px solid var(--border)" }}
        >
          <span
            className="text-[10px] uppercase tracking-widest font-semibold"
            style={{ color: "var(--text-muted)", fontFamily: "var(--font-dm-mono)" }}
          >
            All Engineers
          </span>
          <span
            className="text-[10px]"
            style={{ color: "var(--text-muted)", fontFamily: "var(--font-dm-mono)" }}
          >
            {engineers.length} total
          </span>
        </div>

        {/* Table header */}
        <div
          className="flex-none grid px-3 py-1.5 text-[10px] uppercase tracking-wider"
          style={{
            gridTemplateColumns: "28px 1fr 52px 52px 56px 36px",
            color: "var(--text-muted)",
            fontFamily: "var(--font-dm-mono)",
            borderBottom: "1px solid var(--border)",
            background: "rgba(0,0,0,0.3)",
          }}
        >
          <button className={colBtn} onClick={() => handleSort("rank")}>
            # <SortIcon col="rank" />
          </button>
          <span>Engineer</span>
          <button className={colBtn} onClick={() => handleSort("impactScore")}>
            Impact <SortIcon col="impactScore" />
          </button>
          <button className={colBtn} onClick={() => handleSort("doraScore")}>
            DORA <SortIcon col="doraScore" />
          </button>
          <button className={colBtn} onClick={() => handleSort("pageRankScore")}>
            PRank <SortIcon col="pageRankScore" />
          </button>
          <button className={colBtn} onClick={() => handleSort("prsAuthored")}>
            PRs <SortIcon col="prsAuthored" />
          </button>
        </div>

        {/* Table body — scrollable */}
        <div className="flex-1 overflow-y-auto">
          {sortedAll.map((eng) => {
            const isSelected = selectedLogin === eng.login;
            const isTop5 = eng.rank <= 5;
            return (
              <button
                key={eng.login}
                onClick={() =>
                  onSelectLogin(isSelected ? null : eng.login)
                }
                className={`table-row w-full text-left grid px-3 py-1.5 items-center ${
                  isSelected ? "selected" : ""
                }`}
                style={{
                  gridTemplateColumns: "28px 1fr 52px 52px 56px 36px",
                  borderBottom: "1px solid var(--border)",
                  outline: "none",
                }}
              >
                {/* Rank */}
                <span
                  className="text-[11px] font-medium"
                  style={{
                    color: isTop5 ? "var(--accent)" : "var(--text-muted)",
                    fontFamily: "var(--font-dm-mono)",
                  }}
                >
                  {eng.rank}
                </span>

                {/* Name */}
                <div className="flex items-center gap-1.5 min-w-0">
                  <Image
                    src={eng.avatar_url}
                    alt={eng.login}
                    width={18}
                    height={18}
                    className="rounded-full shrink-0"
                    style={{ opacity: 0.85 }}
                  />
                  <span
                    className="text-[11px] truncate"
                    style={{
                      color: isSelected ? "var(--accent)" : "var(--text-primary)",
                      fontFamily: "var(--font-syne)",
                      fontWeight: isTop5 ? 600 : 400,
                    }}
                  >
                    {eng.login}
                  </span>
                </div>

                {/* Impact */}
                <div className="flex items-center gap-1">
                  <div
                    className="h-1 rounded-full"
                    style={{
                      width: `${Math.round(eng.impactScore * 32)}px`,
                      background: "var(--accent)",
                      opacity: 0.7,
                    }}
                  />
                  <span
                    className="text-[10px] w-6 text-right"
                    style={{
                      color: "var(--text-secondary)",
                      fontFamily: "var(--font-dm-mono)",
                    }}
                  >
                    {(eng.impactScore * 100).toFixed(0)}
                  </span>
                </div>

                {/* DORA */}
                <span
                  className="text-[10px] text-right"
                  style={{
                    color: "var(--text-secondary)",
                    fontFamily: "var(--font-dm-mono)",
                  }}
                >
                  {(eng.doraScore * 100).toFixed(0)}
                </span>

                {/* PageRank */}
                <span
                  className="text-[10px] text-right"
                  style={{
                    color: "var(--text-secondary)",
                    fontFamily: "var(--font-dm-mono)",
                  }}
                >
                  {(eng.pageRankScore * 100).toFixed(0)}
                </span>

                {/* PRs */}
                <span
                  className="text-[10px] text-right"
                  style={{
                    color: "var(--text-muted)",
                    fontFamily: "var(--font-dm-mono)",
                  }}
                >
                  {eng.prsAuthored}
                </span>
              </button>
            );
          })}
        </div>
      </div>
    </div>
  );
}

input.content:
"use client";

import { useCallback, useEffect, useMemo, useRef, useState } from "react";
import dynamic from "next/dynamic";
import Image from "next/image";
import { Engineer, GraphEdge, GraphNode } from "../types";

const ForceGraph2D = dynamic(() => import("react-force-graph-2d"), {
  ssr: false,
  loading: () => (
    <div className="w-full h-full flex items-center justify-center"
      style={{ color: "var(--text-muted)", fontFamily: "var(--font-dm-mono)", fontSize: 12 }}>
      Initialising graph…
    </div>
  ),
});

/* ── Helpers ──────────────────────────────────────────────── */
function lerp(a: number, b: number, t: number) {
  return a + (b - a) * Math.max(0, Math.min(1, t));
}

function nodeRadius(impactScore: number) {
  // Deliberately small: 2–8px in graph-space
  return lerp(2, 8, impactScore);
}

/* ── Selected-node detail panel ─────────────────────────── */
function NodeDetail({
  engineer,
  rank,
  connectedEdges,
  engineerMap,
  onClose,
}: {
  engineer: Engineer;
  rank: number;
  connectedEdges: { source: string; target: string; weight: number }[];
  engineerMap: Map<string, Engineer>;
  onClose: () => void;
}) {
  const d = engineer.dora;
  // Split edges into "reviews given by" (source=engineer) and "reviews received from" (target=engineer)
  const reviewsGivenTo = connectedEdges
    .filter((e) => e.source === engineer.login)
    .sort((a, b) => b.weight - a.weight)
    .slice(0, 5);
  const reviewsReceivedFrom = connectedEdges
    .filter((e) => e.target === engineer.login)
    .sort((a, b) => b.weight - a.weight)
    .slice(0, 5);

  return (
    <div
      className="absolute top-3 right-3 z-20 rounded-xl overflow-hidden"
      style={{
        width: 280,
        background: "rgba(10, 13, 20, 0.95)",
        backdropFilter: "blur(16px)",
        border: "1px solid rgba(249,115,22,0.25)",
        pointerEvents: "auto",
        maxHeight: "calc(100% - 24px)",
        overflowY: "auto",
      }}
    >
      {/* Header */}
      <div className="flex items-center gap-3 p-3 pb-2">
        <Image src={engineer.avatar_url} alt={engineer.login} width={36} height={36}
          className="rounded-full" style={{ border: "2px solid rgba(249,115,22,0.4)" }} />
        <div className="flex-1 min-w-0">
          <div className="text-sm font-bold text-white truncate" style={{ fontFamily: "var(--font-syne)" }}>
            {engineer.login}
          </div>
          <div className="text-[10px]" style={{ color: "var(--accent)", fontFamily: "var(--font-dm-mono)" }}>
            Rank #{rank} · Impact {(engineer.impactScore * 100).toFixed(1)}
          </div>
        </div>
        <button onClick={onClose} className="text-slate-500 hover:text-white transition-colors text-sm leading-none p-1"
          style={{ fontFamily: "var(--font-dm-mono)" }}>✕</button>
      </div>

      {/* Impact formula */}
      <div className="mx-3 mb-2 rounded-md px-2.5 py-1.5 text-[10px]"
        style={{ background: "rgba(255,255,255,0.03)", border: "1px solid rgba(255,255,255,0.05)", fontFamily: "var(--font-dm-mono)" }}>
        <div className="flex items-center gap-1 flex-wrap">
          <span style={{ color: "var(--text-muted)" }}>Impact =</span>
          <span style={{ color: "var(--green)" }}>{(engineer.doraScore * 100).toFixed(0)}</span>
          <span style={{ color: "var(--text-muted)", opacity: 0.5 }}>×.6</span>
          <span style={{ color: "var(--text-muted)" }}>+</span>
          <span style={{ color: "var(--blue)" }}>{(engineer.pageRankScore * 100).toFixed(0)}</span>
          <span style={{ color: "var(--text-muted)", opacity: 0.5 }}>×.4</span>
          <span style={{ color: "var(--text-muted)" }}>=</span>
          <span className="font-bold" style={{ color: "var(--accent)" }}>{(engineer.impactScore * 100).toFixed(1)}</span>
        </div>
      </div>

      {/* DORA breakdown */}
      <div className="mx-3 mb-2">
        <div className="text-[8px] uppercase tracking-widest mb-1"
          style={{ color: "var(--text-muted)", fontFamily: "var(--font-dm-mono)" }}>
          DORA Score: {(engineer.doraScore * 100).toFixed(0)}
        </div>
        <div className="grid grid-cols-4 gap-1.5">
          {[
            { label: "Merge", value: d.mergeFrequency, color: "#10b981" },
            { label: "Lead", value: d.leadTime, color: "#06b6d4" },
            { label: "Fail", value: d.changeFailureRate, color: "#8b5cf6" },
            { label: "Recent", value: d.recencyScore, color: "#f59e0b" },
          ].map((m) => (
            <div key={m.label} className="text-center">
              <div className="text-[11px] font-bold" style={{ color: m.color, fontFamily: "var(--font-dm-mono)" }}>
                {(m.value * 100).toFixed(0)}
              </div>
              <div className="text-[7px] uppercase tracking-wider" style={{ color: "var(--text-muted)", fontFamily: "var(--font-dm-mono)" }}>
                {m.label}
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Stats */}
      <div className="mx-3 mb-2 grid grid-cols-4 gap-1.5">
        {[
          { label: "Merged", v: engineer.prsMerged },
          { label: "Authored", v: engineer.prsAuthored },
          { label: "Rev given", v: engineer.reviewsGiven },
          { label: "Rev recv", v: engineer.reviewsReceived },
        ].map((s) => (
          <div key={s.label} className="text-center">
            <div className="text-[11px] font-semibold text-white" style={{ fontFamily: "var(--font-dm-mono)" }}>{s.v}</div>
            <div className="text-[7px]" style={{ color: "var(--text-muted)", fontFamily: "var(--font-dm-mono)" }}>{s.label}</div>
          </div>
        ))}
      </div>

      {/* Review edges — "showing the work" */}
      {reviewsGivenTo.length > 0 && (
        <div className="mx-3 mb-2">
          <div className="text-[8px] uppercase tracking-widest mb-1"
            style={{ color: "var(--text-muted)", fontFamily: "var(--font-dm-mono)" }}>
            Top reviews given (edge weights)
          </div>
          {reviewsGivenTo.map((e) => {
            const reviewCount = engineer.doraScore > 0 ? Math.round(e.weight / engineer.doraScore) : 0;
            return (
              <div key={e.target} className="flex items-center gap-1.5 text-[9px] py-0.5"
                style={{ fontFamily: "var(--font-dm-mono)" }}>
                <span style={{ color: "var(--text-primary)" }}>→ {e.target}</span>
                <span className="flex-1" />
                <span style={{ color: "var(--text-muted)" }}>{reviewCount}</span>
                <span style={{ color: "var(--text-muted)", opacity: 0.5 }}>×</span>
                <span style={{ color: "var(--green)" }}>{engineer.doraScore.toFixed(2)}</span>
                <span style={{ color: "var(--text-muted)", opacity: 0.5 }}>=</span>
                <span style={{ color: "var(--accent)" }}>{e.weight.toFixed(1)}</span>
              </div>
            );
          })}
        </div>
      )}

      {reviewsReceivedFrom.length > 0 && (
        <div className="mx-3 mb-3">
          <div className="text-[8px] uppercase tracking-widest mb-1"
            style={{ color: "var(--text-muted)", fontFamily: "var(--font-dm-mono)" }}>
            Top reviews received (edge weights)
          </div>
          {reviewsReceivedFrom.map((e) => {
            const reviewer = engineerMap.get(e.source);
            const reviewerDora = reviewer?.doraScore ?? 0;
            const reviewCount = reviewerDora > 0 ? Math.round(e.weight / reviewerDora) : 0;
            return (
              <div key={e.source} className="flex items-center gap-1.5 text-[9px] py-0.5"
                style={{ fontFamily: "var(--font-dm-mono)" }}>
                <span style={{ color: "var(--text-primary)" }}>← {e.source}</span>
                <span className="flex-1" />
                <span style={{ color: "var(--text-muted)" }}>{reviewCount}</span>
                <span style={{ color: "var(--text-muted)", opacity: 0.5 }}>×</span>
                <span style={{ color: "var(--green)" }}>{reviewerDora.toFixed(2)}</span>
                <span style={{ color: "var(--text-muted)", opacity: 0.5 }}>=</span>
                <span style={{ color: "var(--accent)" }}>{e.weight.toFixed(1)}</span>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}

/* ── Edge tooltip (on hover) ─────────────────────────────── */
function EdgeTooltip({
  edge,
  engineerMap,
  pos,
}: {
  edge: { source: string; target: string; weight: number };
  engineerMap: Map<string, Engineer>;
  pos: { x: number; y: number };
}) {
  const reviewer = engineerMap.get(edge.source);
  const reviewerDora = reviewer?.doraScore ?? 0;
  const reviewCount = reviewerDora > 0 ? Math.round(edge.weight / reviewerDora) : 0;

  return (
    <div
      className="absolute z-30 rounded-lg px-3 py-2 pointer-events-none"
      style={{
        left: pos.x + 14,
        top: pos.y - 10,
        background: "rgba(10, 13, 20, 0.95)",
        backdropFilter: "blur(12px)",
        border: "1px solid rgba(249,115,22,0.3)",
        whiteSpace: "nowrap",
      }}
    >
      <div className="text-[10px] mb-1" style={{ fontFamily: "var(--font-dm-mono)" }}>
        <span style={{ color: "var(--accent)" }}>{edge.source}</span>
        <span style={{ color: "var(--text-muted)" }}> reviewed </span>
        <span style={{ color: "var(--blue)" }}>{edge.target}</span>
      </div>
      <div className="text-[10px]" style={{ fontFamily: "var(--font-dm-mono)" }}>
        <span style={{ color: "var(--text-muted)" }}>{reviewCount} reviews</span>
        <span style={{ color: "var(--text-muted)", opacity: 0.5 }}> × </span>
        <span style={{ color: "var(--green)" }}>{reviewerDora.toFixed(2)}</span>
        <span style={{ color: "var(--text-muted)", opacity: 0.5 }}> DORA = </span>
        <span className="font-bold" style={{ color: "var(--accent)" }}>{edge.weight.toFixed(1)}</span>
      </div>
    </div>
  );
}

/* ── Main graph panel ────────────────────────────────────── */
interface Props {
  graph: { nodes: GraphNode[]; edges: GraphEdge[] };
  engineers: Engineer[];
  selectedLogin: string | null;
  onSelectLogin: (login: string | null) => void;
}

export default function GraphPanel({ graph, engineers, selectedLogin, onSelectLogin }: Props) {
  const containerRef = useRef<HTMLDivElement>(null);
  const graphRef = useRef<any>(null);
  const [dims, setDims] = useState({ w: 800, h: 600 });
  const [highlightNodes, setHighlightNodes] = useState(new Set<string>());
  const [highlightLinks, setHighlightLinks] = useState(new Set<string>());
  const [hoveredEdge, setHoveredEdge] = useState<{
    edge: { source: string; target: string; weight: number };
    pos: { x: number; y: number };
  } | null>(null);

  /* ── Lookups ──────────────────────────────────────── */
  const engineerMap = useMemo(() => new Map(engineers.map((e) => [e.login, e])), [engineers]);
  const engineerRankMap = useMemo(() => new Map(engineers.map((e, i) => [e.login, i + 1])), [engineers]);
  const top5 = useMemo(() => new Set(engineers.slice(0, 5).map((e) => e.login)), [engineers]);
  const top20 = useMemo(() => new Set(engineers.slice(0, 20).map((e) => e.login)), [engineers]);

  /* ── Graph data ───────────────────────────────────── */
  const graphData = useMemo(() => {
    const nodes = graph.nodes.map((n) => ({ id: n.id, impactScore: n.impactScore, doraScore: n.doraScore }));
    const links = [...graph.edges]
      .filter((e) => e.weight > 0)
      .sort((a, b) => b.weight - a.weight)
      .slice(0, 800)
      .map((e) => ({ source: e.source, target: e.target, weight: e.weight }));
    return { nodes, links };
  }, [graph]);

  /* ── Link lookup ──────────────────────────────────── */
  const linksByNode = useMemo(() => {
    const map = new Map<string, { neighbor: string; linkKey: string }[]>();
    graphData.links.forEach((link) => {
      const src = typeof link.source === "object" ? (link.source as any).id : link.source;
      const tgt = typeof link.target === "object" ? (link.target as any).id : link.target;
      const key = `${src}→${tgt}`;
      if (!map.has(src)) map.set(src, []);
      if (!map.has(tgt)) map.set(tgt, []);
      map.get(src)!.push({ neighbor: tgt, linkKey: key });
      map.get(tgt)!.push({ neighbor: src, linkKey: key });
    });
    return map;
  }, [graphData.links]);

  /* ── Raw edges for selected node detail ────────── */
  const selectedEdges = useMemo(() => {
    if (!selectedLogin) return [];
    return graphData.links.filter((l) => {
      const src = typeof l.source === "object" ? (l.source as any).id : l.source;
      const tgt = typeof l.target === "object" ? (l.target as any).id : l.target;
      return src === selectedLogin || tgt === selectedLogin;
    }).map((l) => ({
      source: typeof l.source === "object" ? (l.source as any).id : l.source,
      target: typeof l.target === "object" ? (l.target as any).id : l.target,
      weight: l.weight,
    }));
  }, [selectedLogin, graphData.links]);

  /* ── Sync highlight state from selectedLogin ──── */
  useEffect(() => {
    if (!selectedLogin) {
      setHighlightNodes(new Set());
      setHighlightLinks(new Set());
    } else {
      const neighbors = new Set<string>([selectedLogin]);
      const links = new Set<string>();
      (linksByNode.get(selectedLogin) || []).forEach(({ neighbor, linkKey }) => {
        neighbors.add(neighbor);
        links.add(linkKey);
      });
      setHighlightNodes(neighbors);
      setHighlightLinks(links);

      if (graphRef.current) {
        const node = graphData.nodes.find((n) => n.id === selectedLogin);
        if (node && Number.isFinite((node as any).x)) {
          graphRef.current.centerAt((node as any).x, (node as any).y, 600);
          graphRef.current.zoom(3.5, 600);
        }
      }
    }
  }, [selectedLogin, linksByNode, graphData.nodes]);

  /* ── Resize ──────────────────────────────────────── */
  useEffect(() => {
    const el = containerRef.current;
    if (!el) return;
    const obs = new ResizeObserver((entries) => {
      const { width, height } = entries[0].contentRect;
      setDims({ w: Math.floor(width), h: Math.floor(height) });
    });
    obs.observe(el);
    return () => obs.disconnect();
  }, []);

  /* ── Force tuning ────────────────────────────────── */
  useEffect(() => {
    if (!graphRef.current) return;
    const charge = graphRef.current.d3Force("charge");
    if (charge) charge.strength(-60).distanceMax(300);
    const link = graphRef.current.d3Force("link");
    if (link) link.distance(40).strength(0.2);
  }, []);

  /* ── Interaction ─────────────────────────────────── */
  const handleNodeClick = useCallback((node: any) => {
    setHoveredEdge(null);
    const id = node.id as string;
    if (selectedLogin === id) {
      onSelectLogin(null);
    } else {
      onSelectLogin(id);
    }
  }, [selectedLogin, onSelectLogin]);

  const handleBackgroundClick = useCallback(() => {
    onSelectLogin(null);
    setHoveredEdge(null);
  }, [onSelectLogin]);

  const handleLinkHover = useCallback((link: any, event?: MouseEvent) => {
    if (!link || !event || !containerRef.current) {
      setHoveredEdge(null);
      return;
    }
    const rect = containerRef.current.getBoundingClientRect();
    const x = event.clientX - rect.left;
    const y = event.clientY - rect.top;
    if (!Number.isFinite(x) || !Number.isFinite(y)) {
      setHoveredEdge(null);
      return;
    }
    const src = typeof link.source === "object" ? link.source.id : link.source;
    const tgt = typeof link.target === "object" ? link.target.id : link.target;
    setHoveredEdge({ edge: { source: src, target: tgt, weight: link.weight }, pos: { x, y } });
  }, []);

  /* ── Canvas rendering ────────────────────────────── */
  const nodeCanvasObject = useCallback(
    (node: any, ctx: CanvasRenderingContext2D, globalScale: number) => {
      const id = node.id as string;
      const x = node.x as number;
      const y = node.y as number;
      if (!Number.isFinite(x) || !Number.isFinite(y)) return;

      const r = nodeRadius(node.impactScore);
      const isSelected = id === selectedLogin;
      const isTop5 = top5.has(id);
      const isTop20 = top20.has(id);
      const hasHL = highlightNodes.size > 0;
      const dimmed = hasHL && !highlightNodes.has(id);

      // Color
      let color: string;
      if (hasHL) {
        if (dimmed) color = "rgba(20,25,40,0.35)";
        else if (isSelected) color = "#f97316";
        else if (isTop5) color = "#fb923c";
        else color = "#60a5fa";
      } else {
        if (isTop5) color = "#f97316";
        else if ((engineerRankMap.get(id) ?? 100) <= 10) color = "#3b82f6";
        else if ((engineerRankMap.get(id) ?? 100) <= 30) color = "#1d4ed8";
        else color = "#1e3a5f";
      }

      // Subtle glow for selected/top5
      if ((isSelected || (isTop5 && !dimmed)) && !dimmed && Number.isFinite(r)) {
        const grd = ctx.createRadialGradient(x, y, r * 0.5, x, y, r * 2.5);
        grd.addColorStop(0, isSelected ? "rgba(249,115,22,0.35)" : "rgba(249,115,22,0.15)");
        grd.addColorStop(1, "rgba(249,115,22,0)");
        ctx.beginPath();
        ctx.arc(x, y, r * 2.5, 0, Math.PI * 2);
        ctx.fillStyle = grd;
        ctx.fill();
      }

      // Circle
      ctx.beginPath();
      ctx.arc(x, y, r, 0, Math.PI * 2);
      ctx.fillStyle = color;
      ctx.fill();

      // Ring for selected
      if (isSelected) {
        ctx.beginPath();
        ctx.arc(x, y, r + 1.5, 0, Math.PI * 2);
        ctx.strokeStyle = "#f97316";
        ctx.lineWidth = 1;
        ctx.stroke();
      }

      // Label
      const showLabel = isTop20 || globalScale > 3;
      if (showLabel && !dimmed) {
        const fontSize = Math.max(7, 8 / globalScale);
        ctx.font = `${isTop5 ? "bold " : ""}${fontSize}px 'DM Mono', monospace`;
        ctx.textAlign = "center";
        ctx.textBaseline = "top";
        ctx.fillStyle = isSelected ? "#f97316" : isTop5 ? "rgba(255,200,150,0.9)" : "rgba(148,163,184,0.6)";
        ctx.fillText(id, x, y + r + 1.5);
      }
    },
    [selectedLogin, top5, top20, highlightNodes, engineerRankMap]
  );

  const linkCanvasObject = useCallback(
    (link: any, ctx: CanvasRenderingContext2D, globalScale: number) => {
      const src = typeof link.source === "object" ? link.source : { x: 0, y: 0, id: link.source };
      const tgt = typeof link.target === "object" ? link.target : { x: 0, y: 0, id: link.target };
      if (!Number.isFinite(src.x) || !Number.isFinite(tgt.x)) return;

      const srcId = src.id as string;
      const tgtId = tgt.id as string;
      const key = `${srcId}→${tgtId}`;
      const isHL = highlightLinks.has(key);
      const hasHL = highlightNodes.size > 0;
      const w = link.weight as number;

      ctx.beginPath();
      ctx.moveTo(src.x, src.y);
      ctx.lineTo(tgt.x, tgt.y);

      if (hasHL) {
        if (isHL) {
          ctx.strokeStyle = "rgba(249,115,22,0.45)";
          ctx.lineWidth = Math.min(3, Math.max(0.5, w / 20));
        } else {
          ctx.strokeStyle = "rgba(20,25,40,0.1)";
          ctx.lineWidth = 0.2;
        }
      } else {
        ctx.strokeStyle = "rgba(100,116,139,0.08)";
        ctx.lineWidth = Math.min(1.5, Math.max(0.15, w / 40));
      }
      ctx.stroke();

      // Show weight on highlighted edges when zoomed in
      if (isHL && globalScale > 2) {
        const midX = (src.x + tgt.x) / 2;
        const midY = (src.y + tgt.y) / 2;
        const fontSize = Math.max(6, 7 / globalScale);
        const label = w.toFixed(1);

        ctx.font = `${fontSize}px 'DM Mono', monospace`;
        const tw = ctx.measureText(label).width;
        const pad = 2 / globalScale;

        ctx.fillStyle = "rgba(10,13,20,0.8)";
        ctx.fillRect(midX - tw / 2 - pad, midY - fontSize / 2 - pad, tw + pad * 2, fontSize + pad * 2);

        ctx.fillStyle = "rgba(249,115,22,0.8)";
        ctx.textAlign = "center";
        ctx.textBaseline = "middle";
        ctx.fillText(label, midX, midY);
      }
    },
    [highlightLinks, highlightNodes]
  );

  /* ── Selected engineer data ───────────────────── */
  const selectedEngineer = selectedLogin ? engineerMap.get(selectedLogin) : null;
  const selectedRank = selectedLogin ? (engineerRankMap.get(selectedLogin) ?? 0) : 0;

  const LegendDot = ({ color, label }: { color: string; label: string }) => (
    <div className="flex items-center gap-1.5">
      <div className="w-2 h-2 rounded-full shrink-0" style={{ background: color }} />
      <span>{label}</span>
    </div>
  );

  return (
    <div className="flex flex-col flex-1 min-w-0" style={{ background: "var(--bg)" }}>
      {/* Header */}
      <div className="flex-none flex items-center justify-between px-4 py-2"
        style={{ borderBottom: "1px solid var(--border)", background: "var(--bg-panel)", height: 36 }}>
        <span className="text-[10px] uppercase tracking-widest font-semibold"
          style={{ color: "var(--text-muted)", fontFamily: "var(--font-dm-mono)" }}>
          Review Network Graph
        </span>
        <div className="flex items-center gap-4 text-[10px]"
          style={{ color: "var(--text-muted)", fontFamily: "var(--font-dm-mono)" }}>
          <LegendDot color="var(--accent)" label="Top 5" />
          <LegendDot color="#3b82f6" label="Top 10" />
          <LegendDot color="#1d4ed8" label="Top 30" />
          <LegendDot color="#1e3a5f" label="Others" />
          <span className="ml-1 text-[9px]" style={{ opacity: 0.5 }}>
            edge = reviews × reviewer DORA
          </span>
        </div>
      </div>

      {/* Canvas */}
      <div ref={containerRef} className="relative flex-1"
        style={{ background: "radial-gradient(ellipse at center, rgba(15,22,36,1) 0%, rgba(7,9,15,1) 70%)" }}>
        {dims.w > 0 && (
          <ForceGraph2D
            ref={graphRef}
            graphData={graphData}
            width={dims.w}
            height={dims.h}
            backgroundColor="transparent"
            nodeId="id"
            nodeVal={(n: any) => nodeRadius(n.impactScore) * 2}
            nodeRelSize={1}
            nodeCanvasObject={nodeCanvasObject}
            nodeCanvasObjectMode={() => "replace"}
            linkCanvasObject={linkCanvasObject}
            linkCanvasObjectMode={() => "replace"}
            onNodeClick={handleNodeClick}
            onBackgroundClick={handleBackgroundClick}
            onLinkHover={handleLinkHover as any}
            cooldownTicks={200}
            d3AlphaDecay={0.02}
            d3VelocityDecay={0.4}
            enableNodeDrag
            enableZoomInteraction
            enablePanInteraction
          />
        )}

        {/* Edge hover tooltip */}
        {hoveredEdge && (
          <EdgeTooltip edge={hoveredEdge.edge} engineerMap={engineerMap} pos={hoveredEdge.pos} />
        )}

        {/* Selected node detail panel */}
        {selectedEngineer && (
          <NodeDetail
            engineer={selectedEngineer}
            rank={selectedRank}
            connectedEdges={selectedEdges}
            engineerMap={engineerMap}
            onClose={() => onSelectLogin(null)}
          />
        )}

        {/* Hint */}
        {!selectedEngineer && !hoveredEdge && (
          <div className="absolute bottom-3 left-3 text-[10px] pointer-events-none"
            style={{ color: "var(--text-muted)", fontFamily: "var(--font-dm-mono)" }}>
            Click a node to see full breakdown · Hover edges to see the math
          </div>
        )}
      </div>
    </div>
  );
}

toolUseResult.content:
"use client";

import { useCallback, useEffect, useMemo, useRef, useState } from "react";
import dynamic from "next/dynamic";
import Image from "next/image";
import { Engineer, GraphEdge, GraphNode } from "../types";

const ForceGraph2D = dynamic(() => import("react-force-graph-2d"), {
  ssr: false,
  loading: () => (
    <div className="w-full h-full flex items-center justify-center"
      style={{ color: "var(--text-muted)", fontFamily: "var(--font-dm-mono)", fontSize: 12 }}>
      Initialising graph…
    </div>
  ),
});

/* ── Helpers ──────────────────────────────────────────────── */
function lerp(a: number, b: number, t: number) {
  return a + (b - a) * Math.max(0, Math.min(1, t));
}

function nodeRadius(impactScore: number) {
  // Deliberately small: 2–8px in graph-space
  return lerp(2, 8, impactScore);
}

/* ── Selected-node detail panel ─────────────────────────── */
function NodeDetail({
  engineer,
  rank,
  connectedEdges,
  engineerMap,
  onClose,
}: {
  engineer: Engineer;
  rank: number;
  connectedEdges: { source: string; target: string; weight: number }[];
  engineerMap: Map<string, Engineer>;
  onClose: () => void;
}) {
  const d = engineer.dora;
  // Split edges into "reviews given by" (source=engineer) and "reviews received from" (target=engineer)
  const reviewsGivenTo = connectedEdges
    .filter((e) => e.source === engineer.login)
    .sort((a, b) => b.weight - a.weight)
    .slice(0, 5);
  const reviewsReceivedFrom = connectedEdges
    .filter((e) => e.target === engineer.login)
    .sort((a, b) => b.weight - a.weight)
    .slice(0, 5);

  return (
    <div
      className="absolute top-3 right-3 z-20 rounded-xl overflow-hidden"
      style={{
        width: 280,
        background: "rgba(10, 13, 20, 0.95)",
        backdropFilter: "blur(16px)",
        border: "1px solid rgba(249,115,22,0.25)",
        pointerEvents: "auto",
        maxHeight: "calc(100% - 24px)",
        overflowY: "auto",
      }}
    >
      {/* Header */}
      <div className="flex items-center gap-3 p-3 pb-2">
        <Image src={engineer.avatar_url} alt={engineer.login} width={36} height={36}
          className="rounded-full" style={{ border: "2px solid rgba(249,115,22,0.4)" }} />
        <div className="flex-1 min-w-0">
          <div className="text-sm font-bold text-white truncate" style={{ fontFamily: "var(--font-syne)" }}>
            {engineer.login}
          </div>
          <div className="text-[10px]" style={{ color: "var(--accent)", fontFamily: "var(--font-dm-mono)" }}>
            Rank #{rank} · Impact {(engineer.impactScore * 100).toFixed(1)}
          </div>
        </div>
        <button onClick={onClose} className="text-slate-500 hover:text-white transition-colors text-sm leading-none p-1"
          style={{ fontFamily: "var(--font-dm-mono)" }}>✕</button>
      </div>

      {/* Impact formula */}
      <div className="mx-3 mb-2 rounded-md px-2.5 py-1.5 text-[10px]"
        style={{ background: "rgba(255,255,255,0.03)", border: "1px solid rgba(255,255,255,0.05)", fontFamily: "var(--font-dm-mono)" }}>
        <div className="flex items-center gap-1 flex-wrap">
          <span style={{ color: "var(--text-muted)" }}>Impact =</span>
          <span style={{ color: "var(--green)" }}>{(engineer.doraScore * 100).toFixed(0)}</span>
          <span style={{ color: "var(--text-muted)", opacity: 0.5 }}>×.6</span>
          <span style={{ color: "var(--text-muted)" }}>+</span>
          <span style={{ color: "var(--blue)" }}>{(engineer.pageRankScore * 100).toFixed(0)}</span>
          <span style={{ color: "var(--text-muted)", opacity: 0.5 }}>×.4</span>
          <span style={{ color: "var(--text-muted)" }}>=</span>
          <span className="font-bold" style={{ color: "var(--accent)" }}>{(engineer.impactScore * 100).toFixed(1)}</span>
        </div>
      </div>

      {/* DORA breakdown */}
      <div className="mx-3 mb-2">
        <div className="text-[8px] uppercase tracking-widest mb-1"
          style={{ color: "var(--text-muted)", fontFamily: "var(--font-dm-mono)" }}>
          DORA Score: {(engineer.doraScore * 100).toFixed(0)}
        </div>
        <div className="grid grid-cols-4 gap-1.5">
          {[
            { label: "Merge", value: d.mergeFrequency, color: "#10b981" },
            { label: "Lead", value: d.leadTime, color: "#06b6d4" },
            { label: "Fail", value: d.changeFailureRate, color: "#8b5cf6" },
            { label: "Recent", value: d.recencyScore, color: "#f59e0b" },
          ].map((m) => (
            <div key={m.label} className="text-center">
              <div className="text-[11px] font-bold" style={{ color: m.color, fontFamily: "var(--font-dm-mono)" }}>
                {(m.value * 100).toFixed(0)}
              </div>
              <div className="text-[7px] uppercase tracking-wider" style={{ color: "var(--text-muted)", fontFamily: "var(--font-dm-mono)" }}>
                {m.label}
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Stats */}
      <div className="mx-3 mb-2 grid grid-cols-4 gap-1.5">
        {[
          { label: "Merged", v: engineer.prsMerged },
          { label: "Authored", v: engineer.prsAuthored },
          { label: "Rev given", v: engineer.reviewsGiven },
          { label: "Rev recv", v: engineer.reviewsReceived },
        ].map((s) => (
          <div key={s.label} className="text-center">
            <div className="text-[11px] font-semibold text-white" style={{ fontFamily: "var(--font-dm-mono)" }}>{s.v}</div>
            <div className="text-[7px]" style={{ color: "var(--text-muted)", fontFamily: "var(--font-dm-mono)" }}>{s.label}</div>
          </div>
        ))}
      </div>

      {/* Review edges — "showing the work" */}
      {reviewsGivenTo.length > 0 && (
        <div className="mx-3 mb-2">
          <div className="text-[8px] uppercase tracking-widest mb-1"
            style={{ color: "var(--text-muted)", fontFamily: "var(--font-dm-mono)" }}>
            Top reviews given (edge weights)
          </div>
          {reviewsGivenTo.map((e) => {
            const reviewCount = engineer.doraScore > 0 ? Math.round(e.weight / engineer.doraScore) : 0;
            return (
              <div key={e.target} className="flex items-center gap-1.5 text-[9px] py-0.5"
                style={{ fontFamily: "var(--font-dm-mono)" }}>
                <span style={{ color: "var(--text-primary)" }}>→ {e.target}</span>
                <span className="flex-1" />
                <span style={{ color: "var(--text-muted)" }}>{reviewCount}</span>
                <span style={{ color: "var(--text-muted)", opacity: 0.5 }}>×</span>
                <span style={{ color: "var(--green)" }}>{engineer.doraScore.toFixed(2)}</span>
                <span style={{ color: "var(--text-muted)", opacity: 0.5 }}>=</span>
                <span style={{ color: "var(--accent)" }}>{e.weight.toFixed(1)}</span>
              </div>
            );
          })}
        </div>
      )}

      {reviewsReceivedFrom.length > 0 && (
        <div className="mx-3 mb-3">
          <div className="text-[8px] uppercase tracking-widest mb-1"
            style={{ color: "var(--text-muted)", fontFamily: "var(--font-dm-mono)" }}>
            Top reviews received (edge weights)
          </div>
          {reviewsReceivedFrom.map((e) => {
            const reviewer = engineerMap.get(e.source);
            const reviewerDora = reviewer?.doraScore ?? 0;
            const reviewCount = reviewerDora > 0 ? Math.round(e.weight / reviewerDora) : 0;
            return (
              <div key={e.source} className="flex items-center gap-1.5 text-[9px] py-0.5"
                style={{ fontFamily: "var(--font-dm-mono)" }}>
                <span style={{ color: "var(--text-primary)" }}>← {e.source}</span>
                <span className="flex-1" />
                <span style={{ color: "var(--text-muted)" }}>{reviewCount}</span>
                <span style={{ color: "var(--text-muted)", opacity: 0.5 }}>×</span>
                <span style={{ color: "var(--green)" }}>{reviewerDora.toFixed(2)}</span>
                <span style={{ color: "var(--text-muted)", opacity: 0.5 }}>=</span>
                <span style={{ color: "var(--accent)" }}>{e.weight.toFixed(1)}</span>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}

/* ── Edge tooltip (on hover) ─────────────────────────────── */
function EdgeTooltip({
  edge,
  engineerMap,
  pos,
}: {
  edge: { source: string; target: string; weight: number };
  engineerMap: Map<string, Engineer>;
  pos: { x: number; y: number };
}) {
  const reviewer = engineerMap.get(edge.source);
  const reviewerDora = reviewer?.doraScore ?? 0;
  const reviewCount = reviewerDora > 0 ? Math.round(edge.weight / reviewerDora) : 0;

  return (
    <div
      className="absolute z-30 rounded-lg px-3 py-2 pointer-events-none"
      style={{
        left: pos.x + 14,
        top: pos.y - 10,
        background: "rgba(10, 13, 20, 0.95)",
        backdropFilter: "blur(12px)",
        border: "1px solid rgba(249,115,22,0.3)",
        whiteSpace: "nowrap",
      }}
    >
      <div className="text-[10px] mb-1" style={{ fontFamily: "var(--font-dm-mono)" }}>
        <span style={{ color: "var(--accent)" }}>{edge.source}</span>
        <span style={{ color: "var(--text-muted)" }}> reviewed </span>
        <span style={{ color: "var(--blue)" }}>{edge.target}</span>
      </div>
      <div className="text-[10px]" style={{ fontFamily: "var(--font-dm-mono)" }}>
        <span style={{ color: "var(--text-muted)" }}>{reviewCount} reviews</span>
        <span style={{ color: "var(--text-muted)", opacity: 0.5 }}> × </span>
        <span style={{ color: "var(--green)" }}>{reviewerDora.toFixed(2)}</span>
        <span style={{ color: "var(--text-muted)", opacity: 0.5 }}> DORA = </span>
        <span className="font-bold" style={{ color: "var(--accent)" }}>{edge.weight.toFixed(1)}</span>
      </div>
    </div>
  );
}

/* ── Main graph panel ────────────────────────────────────── */
interface Props {
  graph: { nodes: GraphNode[]; edges: GraphEdge[] };
  engineers: Engineer[];
  selectedLogin: string | null;
  onSelectLogin: (login: string | null) => void;
}

export default function GraphPanel({ graph, engineers, selectedLogin, onSelectLogin }: Props) {
  const containerRef = useRef<HTMLDivElement>(null);
  const graphRef = useRef<any>(null);
  const [dims, setDims] = useState({ w: 800, h: 600 });
  const [highlightNodes, setHighlightNodes] = useState(new Set<string>());
  const [highlightLinks, setHighlightLinks] = useState(new Set<string>());
  const [hoveredEdge, setHoveredEdge] = useState<{
    edge: { source: string; target: string; weight: number };
    pos: { x: number; y: number };
  } | null>(null);

  /* ── Lookups ──────────────────────────────────────── */
  const engineerMap = useMemo(() => new Map(engineers.map((e) => [e.login, e])), [engineers]);
  const engineerRankMap = useMemo(() => new Map(engineers.map((e, i) => [e.login, i + 1])), [engineers]);
  const top5 = useMemo(() => new Set(engineers.slice(0, 5).map((e) => e.login)), [engineers]);
  const top20 = useMemo(() => new Set(engineers.slice(0, 20).map((e) => e.login)), [engineers]);

  /* ── Graph data ───────────────────────────────────── */
  const graphData = useMemo(() => {
    const nodes = graph.nodes.map((n) => ({ id: n.id, impactScore: n.impactScore, doraScore: n.doraScore }));
    const links = [...graph.edges]
      .filter((e) => e.weight > 0)
      .sort((a, b) => b.weight - a.weight)
      .slice(0, 800)
      .map((e) => ({ source: e.source, target: e.target, weight: e.weight }));
    return { nodes, links };
  }, [graph]);

  /* ── Link lookup ──────────────────────────────────── */
  const linksByNode = useMemo(() => {
    const map = new Map<string, { neighbor: string; linkKey: string }[]>();
    graphData.links.forEach((link) => {
      const src = typeof link.source === "object" ? (link.source as any).id : link.source;
      const tgt = typeof link.target === "object" ? (link.target as any).id : link.target;
      const key = `${src}→${tgt}`;
      if (!map.has(src)) map.set(src, []);
      if (!map.has(tgt)) map.set(tgt, []);
      map.get(src)!.push({ neighbor: tgt, linkKey: key });
      map.get(tgt)!.push({ neighbor: src, linkKey: key });
    });
    return map;
  }, [graphData.links]);

  /* ── Raw edges for selected node detail ────────── */
  const selectedEdges = useMemo(() => {
    if (!selectedLogin) return [];
    return graphData.links.filter((l) => {
      const src = typeof l.source === "object" ? (l.source as any).id : l.source;
      const tgt = typeof l.target === "object" ? (l.target as any).id : l.target;
      return src === selectedLogin || tgt === selectedLogin;
    }).map((l) => ({
      source: typeof l.source === "object" ? (l.source as any).id : l.source,
      target: typeof l.target === "object" ? (l.target as any).id : l.target,
      weight: l.weight,
    }));
  }, [selectedLogin, graphData.links]);

  /* ── Sync highlight state from selectedLogin ──── */
  useEffect(() => {
    if (!selectedLogin) {
      setHighlightNodes(new Set());
      setHighlightLinks(new Set());
    } else {
      const neighbors = new Set<string>([selectedLogin]);
      const links = new Set<string>();
      (linksByNode.get(selectedLogin) || []).forEach(({ neighbor, linkKey }) => {
        neighbors.add(neighbor);
        links.add(linkKey);
      });
      setHighlightNodes(neighbors);
      setHighlightLinks(links);

      if (graphRef.current) {
        const node = graphData.nodes.find((n) => n.id === selectedLogin);
        if (node && Number.isFinite((node as any).x)) {
          graphRef.current.centerAt((node as any).x, (node as any).y, 600);
          graphRef.current.zoom(3.5, 600);
        }
      }
    }
  }, [selectedLogin, linksByNode, graphData.nodes]);

  /* ── Resize ──────────────────────────────────────── */
  useEffect(() => {
    const el = containerRef.current;
    if (!el) return;
    const obs = new ResizeObserver((entries) => {
      const { width, height } = entries[0].contentRect;
      setDims({ w: Math.floor(width), h: Math.floor(height) });
    });
    obs.observe(el);
    return () => obs.disconnect();
  }, []);

  /* ── Force tuning ────────────────────────────────── */
  useEffect(() => {
    if (!graphRef.current) return;
    const charge = graphRef.current.d3Force("charge");
    if (charge) charge.strength(-60).distanceMax(300);
    const link = graphRef.current.d3Force("link");
    if (link) link.distance(40).strength(0.2);
  }, []);

  /* ── Interaction ─────────────────────────────────── */
  const handleNodeClick = useCallback((node: any) => {
    setHoveredEdge(null);
    const id = node.id as string;
    if (selectedLogin === id) {
      onSelectLogin(null);
    } else {
      onSelectLogin(id);
    }
  }, [selectedLogin, onSelectLogin]);

  const handleBackgroundClick = useCallback(() => {
    onSelectLogin(null);
    setHoveredEdge(null);
  }, [onSelectLogin]);

  const handleLinkHover = useCallback((link: any, event?: MouseEvent) => {
    if (!link || !event || !containerRef.current) {
      setHoveredEdge(null);
      return;
    }
    const rect = containerRef.current.getBoundingClientRect();
    const x = event.clientX - rect.left;
    const y = event.clientY - rect.top;
    if (!Number.isFinite(x) || !Number.isFinite(y)) {
      setHoveredEdge(null);
      return;
    }
    const src = typeof link.source === "object" ? link.source.id : link.source;
    const tgt = typeof link.target === "object" ? link.target.id : link.target;
    setHoveredEdge({ edge: { source: src, target: tgt, weight: link.weight }, pos: { x, y } });
  }, []);

  /* ── Canvas rendering ────────────────────────────── */
  const nodeCanvasObject = useCallback(
    (node: any, ctx: CanvasRenderingContext2D, globalScale: number) => {
      const id = node.id as string;
      const x = node.x as number;
      const y = node.y as number;
      if (!Number.isFinite(x) || !Number.isFinite(y)) return;

      const r = nodeRadius(node.impactScore);
      const isSelected = id === selectedLogin;
      const isTop5 = top5.has(id);
      const isTop20 = top20.has(id);
      const hasHL = highlightNodes.size > 0;
      const dimmed = hasHL && !highlightNodes.has(id);

      // Color
      let color: string;
      if (hasHL) {
        if (dimmed) color = "rgba(20,25,40,0.35)";
        else if (isSelected) color = "#f97316";
        else if (isTop5) color = "#fb923c";
        else color = "#60a5fa";
      } else {
        if (isTop5) color = "#f97316";
        else if ((engineerRankMap.get(id) ?? 100) <= 10) color = "#3b82f6";
        else if ((engineerRankMap.get(id) ?? 100) <= 30) color = "#1d4ed8";
        else color = "#1e3a5f";
      }

      // Subtle glow for selected/top5
      if ((isSelected || (isTop5 && !dimmed)) && !dimmed && Number.isFinite(r)) {
        const grd = ctx.createRadialGradient(x, y, r * 0.5, x, y, r * 2.5);
        grd.addColorStop(0, isSelected ? "rgba(249,115,22,0.35)" : "rgba(249,115,22,0.15)");
        grd.addColorStop(1, "rgba(249,115,22,0)");
        ctx.beginPath();
        ctx.arc(x, y, r * 2.5, 0, Math.PI * 2);
        ctx.fillStyle = grd;
        ctx.fill();
      }

      // Circle
      ctx.beginPath();
      ctx.arc(x, y, r, 0, Math.PI * 2);
      ctx.fillStyle = color;
      ctx.fill();

      // Ring for selected
      if (isSelected) {
        ctx.beginPath();
        ctx.arc(x, y, r + 1.5, 0, Math.PI * 2);
        ctx.strokeStyle = "#f97316";
        ctx.lineWidth = 1;
        ctx.stroke();
      }

      // Label
      const showLabel = isTop20 || globalScale > 3;
      if (showLabel && !dimmed) {
        const fontSize = Math.max(7, 8 / globalScale);
        ctx.font = `${isTop5 ? "bold " : ""}${fontSize}px 'DM Mono', monospace`;
        ctx.textAlign = "center";
        ctx.textBaseline = "top";
        ctx.fillStyle = isSelected ? "#f97316" : isTop5 ? "rgba(255,200,150,0.9)" : "rgba(148,163,184,0.6)";
        ctx.fillText(id, x, y + r + 1.5);
      }
    },
    [selectedLogin, top5, top20, highlightNodes, engineerRankMap]
  );

  const linkCanvasObject = useCallback(
    (link: any, ctx: CanvasRenderingContext2D, globalScale: number) => {
      const src = typeof link.source === "object" ? link.source : { x: 0, y: 0, id: link.source };
      const tgt = typeof link.target === "object" ? link.target : { x: 0, y: 0, id: link.target };
      if (!Number.isFinite(src.x) || !Number.isFinite(tgt.x)) return;

      const srcId = src.id as string;
      const tgtId = tgt.id as string;
      const key = `${srcId}→${tgtId}`;
      const isHL = highlightLinks.has(key);
      const hasHL = highlightNodes.size > 0;
      const w = link.weight as number;

      ctx.beginPath();
      ctx.moveTo(src.x, src.y);
      ctx.lineTo(tgt.x, tgt.y);

      if (hasHL) {
        if (isHL) {
          ctx.strokeStyle = "rgba(249,115,22,0.45)";
          ctx.lineWidth = Math.min(3, Math.max(0.5, w / 20));
        } else {
          ctx.strokeStyle = "rgba(20,25,40,0.1)";
          ctx.lineWidth = 0.2;
        }
      } else {
        ctx.strokeStyle = "rgba(100,116,139,0.08)";
        ctx.lineWidth = Math.min(1.5, Math.max(0.15, w / 40));
      }
      ctx.stroke();

      // Show weight on highlighted edges when zoomed in
      if (isHL && globalScale > 2) {
        const midX = (src.x + tgt.x) / 2;
        const midY = (src.y + tgt.y) / 2;
        const fontSize = Math.max(6, 7 / globalScale);
        const label = w.toFixed(1);

        ctx.font = `${fontSize}px 'DM Mono', monospace`;
        const tw = ctx.measureText(label).width;
        const pad = 2 / globalScale;

        ctx.fillStyle = "rgba(10,13,20,0.8)";
        ctx.fillRect(midX - tw / 2 - pad, midY - fontSize / 2 - pad, tw + pad * 2, fontSize + pad * 2);

        ctx.fillStyle = "rgba(249,115,22,0.8)";
        ctx.textAlign = "center";
        ctx.textBaseline = "middle";
        ctx.fillText(label, midX, midY);
      }
    },
    [highlightLinks, highlightNodes]
  );

  /* ── Selected engineer data ───────────────────── */
  const selectedEngineer = selectedLogin ? engineerMap.get(selectedLogin) : null;
  const selectedRank = selectedLogin ? (engineerRankMap.get(selectedLogin) ?? 0) : 0;

  const LegendDot = ({ color, label }: { color: string; label: string }) => (
    <div className="flex items-center gap-1.5">
      <div className="w-2 h-2 rounded-full shrink-0" style={{ background: color }} />
      <span>{label}</span>
    </div>
  );

  return (
    <div className="flex flex-col flex-1 min-w-0" style={{ background: "var(--bg)" }}>
      {/* Header */}
      <div className="flex-none flex items-center justify-between px-4 py-2"
        style={{ borderBottom: "1px solid var(--border)", background: "var(--bg-panel)", height: 36 }}>
        <span className="text-[10px] uppercase tracking-widest font-semibold"
          style={{ color: "var(--text-muted)", fontFamily: "var(--font-dm-mono)" }}>
          Review Network Graph
        </span>
        <div className="flex items-center gap-4 text-[10px]"
          style={{ color: "var(--text-muted)", fontFamily: "var(--font-dm-mono)" }}>
          <LegendDot color="var(--accent)" label="Top 5" />
          <LegendDot color="#3b82f6" label="Top 10" />
          <LegendDot color="#1d4ed8" label="Top 30" />
          <LegendDot color="#1e3a5f" label="Others" />
          <span className="ml-1 text-[9px]" style={{ opacity: 0.5 }}>
            edge = reviews × reviewer DORA
          </span>
        </div>
      </div>

      {/* Canvas */}
      <div ref={containerRef} className="relative flex-1"
        style={{ background: "radial-gradient(ellipse at center, rgba(15,22,36,1) 0%, rgba(7,9,15,1) 70%)" }}>
        {dims.w > 0 && (
          <ForceGraph2D
            ref={graphRef}
            graphData={graphData}
            width={dims.w}
            height={dims.h}
            backgroundColor="transparent"
            nodeId="id"
            nodeVal={(n: any) => nodeRadius(n.impactScore) * 2}
            nodeRelSize={1}
            nodeCanvasObject={nodeCanvasObject}
            nodeCanvasObjectMode={() => "replace"}
            linkCanvasObject={linkCanvasObject}
            linkCanvasObjectMode={() => "replace"}
            onNodeClick={handleNodeClick}
            onBackgroundClick={handleBackgroundClick}
            onLinkHover={handleLinkHover as any}
            cooldownTicks={200}
            d3AlphaDecay={0.02}
            d3VelocityDecay={0.4}
            enableNodeDrag
            enableZoomInteraction
            enablePanInteraction
          />
        )}

        {/* Edge hover tooltip */}
        {hoveredEdge && (
          <EdgeTooltip edge={hoveredEdge.edge} engineerMap={engineerMap} pos={hoveredEdge.pos} />
        )}

        {/* Selected node detail panel */}
        {selectedEngineer && (
          <NodeDetail
            engineer={selectedEngineer}
            rank={selectedRank}
            connectedEdges={selectedEdges}
            engineerMap={engineerMap}
            onClose={() => onSelectLogin(null)}
          />
        )}

        {/* Hint */}
        {!selectedEngineer && !hoveredEdge && (
          <div className="absolute bottom-3 left-3 text-[10px] pointer-events-none"
            style={{ color: "var(--text-muted)", fontFamily: "var(--font-dm-mono)" }}>
            Click a node to see full breakdown · Hover edges to see the math
          </div>
        )}
      </div>
    </div>
  );
}

