"use client";

import Image from "next/image";
import { Engineer } from "../types";

/* ── Mini progress bar ──────────────────────────── */
function Bar({ value, color, h = 3 }: { value: number; color: string; h?: number }) {
  return (
    <div className="flex-1 rounded-full overflow-hidden" style={{ height: h, background: "rgba(255,255,255,0.04)" }}>
      <div className="h-full rounded-full score-fill" style={{ width: `${Math.round(value * 100)}%`, background: color }} />
    </div>
  );
}

/* ── Sub-metric row ─────────────────────────────── */
function Sub({ label, value, color }: { label: string; value: number; color: string }) {
  return (
    <div className="flex items-center gap-1">
      <span className="w-[46px] shrink-0 text-[7.5px]" style={{ color: "var(--text-muted)", fontFamily: "var(--font-dm-mono)" }}>
        {label}
      </span>
      <Bar value={value} color={color} h={2} />
      <span className="w-4 text-right text-[7.5px] shrink-0" style={{ color, fontFamily: "var(--font-dm-mono)" }}>
        {(value * 100).toFixed(0)}
      </span>
    </div>
  );
}

/* ── Pillar block ───────────────────────────────── */
function Pillar({
  label,
  score,
  color,
  dimColor,
  children,
}: {
  label: string;
  score: number;
  color: string;
  dimColor: string;
  children?: React.ReactNode;
}) {
  return (
    <div className="flex-1 min-w-0 rounded-md px-2 py-1.5" style={{ background: dimColor }}>
      <div className="flex items-baseline justify-between mb-1">
        <span className="text-[7.5px] uppercase tracking-[0.08em] font-medium" style={{ color: "var(--text-muted)", fontFamily: "var(--font-dm-mono)" }}>
          {label}
        </span>
        <span className="text-[11px] font-bold tabular-nums" style={{ color, fontFamily: "var(--font-dm-mono)" }}>
          {(score * 100).toFixed(0)}
        </span>
      </div>
      <Bar value={score} color={color} />
      {children && <div className="mt-1.5 flex flex-col gap-px">{children}</div>}
    </div>
  );
}

/* ── Rank indicator ─────────────────────────────── */
function Rank({ rank }: { rank: number }) {
  const cfg: Record<number, { bg: string; fg: string; shadow?: string }> = {
    1: { bg: "var(--accent)", fg: "#fff", shadow: "0 0 16px rgba(249,115,22,0.4)" },
    2: { bg: "rgba(148,163,184,0.15)", fg: "#94a3b8" },
    3: { bg: "rgba(251,191,36,0.12)", fg: "#fbbf24" },
  };
  const c = cfg[rank] ?? { bg: "rgba(71,85,105,0.12)", fg: "#64748b" };
  return (
    <div
      className="w-6 h-6 rounded-full flex items-center justify-center text-[10px] font-bold shrink-0"
      style={{ background: c.bg, color: c.fg, boxShadow: c.shadow, fontFamily: "var(--font-dm-mono)" }}
    >
      {rank}
    </div>
  );
}

/* ── Engineer card ──────────────────────────────── */
function Card({
  engineer: e,
  rank,
  selected,
  onClick,
  delay,
}: {
  engineer: Engineer;
  rank: number;
  selected: boolean;
  onClick: () => void;
  delay: number;
}) {
  const isFirst = rank === 1;

  return (
    <button
      onClick={onClick}
      className="engineer-card card-animate w-full text-left rounded-xl border"
      style={{
        animationDelay: `${delay}ms`,
        borderColor: selected
          ? "rgba(249,115,22,0.45)"
          : isFirst
          ? "rgba(249,115,22,0.2)"
          : "var(--border)",
        background: selected
          ? "rgba(249,115,22,0.05)"
          : isFirst
          ? "rgba(249,115,22,0.03)"
          : "var(--bg-card)",
        padding: "10px 12px",
        outline: "none",
      }}
    >
      {/* Header row */}
      <div className="flex items-center gap-2.5 mb-2">
        <Rank rank={rank} />
        <Image
          src={e.avatar_url}
          alt={e.login}
          width={28}
          height={28}
          className="rounded-full shrink-0"
          style={{
            border: isFirst
              ? "2px solid rgba(249,115,22,0.4)"
              : "1.5px solid rgba(255,255,255,0.08)",
          }}
        />
        <div className="flex-1 min-w-0">
          <div
            className="text-[13px] font-bold text-white leading-none truncate"
            style={{ fontFamily: "var(--font-syne)", letterSpacing: "-0.01em" }}
          >
            {e.login}
          </div>
          <div
            className="text-[9px] mt-0.5 truncate"
            style={{ color: "var(--text-muted)", fontFamily: "var(--font-dm-mono)" }}
          >
            {e.prsMerged} merged · {e.reviewsGiven} reviews · {(e.mergeReliability * 100).toFixed(0)}% reliability
          </div>
        </div>
        <div className="text-right shrink-0 pl-2">
          <div
            className="text-xl font-bold leading-none tabular-nums"
            style={{
              color: isFirst ? "var(--accent)" : "var(--text-primary)",
              fontFamily: "var(--font-dm-mono)",
              letterSpacing: "-0.02em",
            }}
          >
            {(e.impactScore * 100).toFixed(1)}
          </div>
          <div
            className="text-[7px] uppercase tracking-[0.1em] mt-0.5"
            style={{ color: "var(--text-muted)", fontFamily: "var(--font-dm-mono)" }}
          >
            impact
          </div>
        </div>
      </div>

      {/* Formula — compact, readable */}
      <div
        className="rounded-md px-2.5 py-1 mb-2 text-[9px]"
        style={{
          background: "rgba(255,255,255,0.015)",
          border: "1px solid rgba(255,255,255,0.03)",
          fontFamily: "var(--font-dm-mono)",
        }}
      >
        <span style={{ color: "var(--text-muted)" }}>
          <span style={{ color: "#10b981" }}>{(e.executionQualityScore * 100).toFixed(0)}</span>
          <span style={{ opacity: 0.35 }}> ×.4 </span>
          <span style={{ opacity: 0.3 }}>+</span>
          <span style={{ color: "#3b82f6" }}> {(e.collaborationScore * 100).toFixed(0)}</span>
          <span style={{ opacity: 0.35 }}> ×.3 </span>
          <span style={{ opacity: 0.3 }}>+</span>
          <span style={{ color: "#a78bfa" }}> {(e.codeHealthScore * 100).toFixed(0)}</span>
          <span style={{ opacity: 0.35 }}> ×.3 </span>
          <span style={{ opacity: 0.3 }}>=</span>
          <span className="font-bold" style={{ color: "var(--accent)" }}> {(e.impactScore * 100).toFixed(1)}</span>
        </span>
      </div>

      {/* 3 Pillars */}
      <div className="flex gap-1.5">
        <Pillar label="Execution" score={e.executionQualityScore} color="#10b981" dimColor="rgba(16,185,129,0.04)">
          <Sub label="Cadence" value={e.executionQuality.mergeCadence} color="#10b981" />
          <Sub label="Lead tm" value={e.executionQuality.leadTime} color="#06b6d4" />
          <Sub label="Fail rt" value={e.executionQuality.changeFailureRate} color="#8b5cf6" />
          <Sub label="Recent" value={e.executionQuality.recencyScore} color="#f59e0b" />
          <Sub label="Effort" value={e.executionQuality.prEffortScore} color="#ec4899" />
        </Pillar>

        <Pillar label="Collab" score={e.collaborationScore} color="#3b82f6" dimColor="rgba(59,130,246,0.04)">
          <div className="flex flex-col gap-0.5 text-[7.5px]" style={{ color: "var(--text-muted)", fontFamily: "var(--font-dm-mono)" }}>
            <span>PageRank {(e.collaborationScore * 100).toFixed(0)}</span>
            <span>{e.reviewsGiven} reviews given</span>
            <span>{e.avgCommentsPerReview.toFixed(1)} avg comments</span>
          </div>
        </Pillar>

        <Pillar label="Health" score={e.codeHealthScore} color="#a78bfa" dimColor="rgba(167,139,250,0.04)">
          <div className="flex flex-col gap-0.5 text-[7.5px]" style={{ color: "var(--text-muted)", fontFamily: "var(--font-dm-mono)" }}>
            <span>Churn {(e.churnRate * 100).toFixed(0)}%</span>
            <span>Reliability {(e.mergeReliability * 100).toFixed(0)}%</span>
          </div>
        </Pillar>
      </div>

      {/* Summary */}
      <p
        className="text-[8px] leading-relaxed mt-2 pt-1.5 line-clamp-2"
        style={{ color: "var(--text-muted)", borderTop: "1px solid rgba(255,255,255,0.03)", fontFamily: "var(--font-dm-mono)" }}
      >
        {e.summary}
      </p>
    </button>
  );
}

/* ── Panel ──────────────────────────────────────── */
interface Props {
  engineers: Engineer[];
  selectedLogin: string | null;
  onSelectLogin: (login: string | null) => void;
}

export default function LeaderboardPanel({ engineers, selectedLogin, onSelectLogin }: Props) {
  const top5 = engineers.slice(0, 5);

  return (
    <div
      className="flex flex-col overflow-hidden"
      style={{
        width: 480,
        flexShrink: 0,
        borderRight: "1px solid var(--border)",
        background: "var(--bg-panel)",
      }}
    >
      <div className="flex-none px-4 pt-3 pb-2">
        <div
          className="text-[9px] uppercase tracking-[0.12em] font-semibold"
          style={{ color: "var(--text-muted)", fontFamily: "var(--font-dm-mono)" }}
        >
          Top 5 Engineers by Impact Score
        </div>
        <p
          className="text-[8.5px] mt-0.5"
          style={{ color: "var(--text-muted)", fontFamily: "var(--font-dm-mono)", opacity: 0.5 }}
        >
          Full calculation shown per card. Click to explore in graph.
        </p>
      </div>

      <div className="flex-1 px-3 pb-3 overflow-y-auto">
        <div className="flex flex-col gap-2">
          {top5.map((eng, i) => (
            <Card
              key={eng.login}
              engineer={eng}
              rank={i + 1}
              delay={i * 80}
              selected={selectedLogin === eng.login}
              onClick={() => onSelectLogin(selectedLogin === eng.login ? null : eng.login)}
            />
          ))}
        </div>
      </div>
    </div>
  );
}

