import type { Metadata } from "next";
import { Syne, DM_Mono } from "next/font/google";
import "./globals.css";

const syne = Syne({
  subsets: ["latin"],
  variable: "--font-syne",
  weight: ["400", "500", "600", "700", "800"],
  display: "swap",
});

const dmMono = DM_Mono({
  subsets: ["latin"],
  variable: "--font-dm-mono",
  weight: ["300", "400", "500"],
  display: "swap",
});

export const metadata: Metadata = {
  title: "PostHog Engineering Impact Dashboard",
  description:
    "Analyzing 90 days of GitHub data using DORA metrics + Review Network PageRank",
};

export default function RootLayout({
  children,
}: Readonly<{ children: React.ReactNode }>) {
  return (
    <html lang="en" className={`${syne.variable} ${dmMono.variable} h-full`}>
      <body className="h-full antialiased">{children}</body>
    </html>
  );
}

  rank,
  connectedEdges,
  engineerMap,
  onClose,
}: {
  engineer: Engineer;
  rank: number;
  connectedEdges: { source: string; target: string; weight: number }[];
  engineerMap: Map<string, Engineer>;
  onClose: () => void;
}) {
  const reviewsGiven = connectedEdges
    .filter((e) => e.source === engineer.login)
    .sort((a, b) => b.weight - a.weight)
    .slice(0, 5);
  const reviewsReceived = connectedEdges
    .filter((e) => e.target === engineer.login)
    .sort((a, b) => b.weight - a.weight)
    .slice(0, 5);

  const eq = engineer.executionQuality;

  return (
    <div
      className="absolute top-3 right-3 z-20 rounded-xl detail-slide-in"
      style={{
        width: 260,
        background: "rgba(9, 12, 20, 0.96)",
        backdropFilter: "blur(20px)",
        border: "1px solid rgba(249,115,22,0.2)",
        boxShadow: "0 8px 32px rgba(0,0,0,0.4)",
        pointerEvents: "auto",
        maxHeight: "calc(100% - 24px)",
        overflowY: "auto",
      }}
    >
      {/* Header */}
      <div className="flex items-center gap-2.5 p-3 pb-2">
        <Image
          src={engineer.avatar_url}
          alt={engineer.login}
          width={32}
          height={32}
          className="rounded-full"
          style={{ border: "2px solid rgba(249,115,22,0.35)" }}
        />
        <div className="flex-1 min-w-0">
          <div className="text-[12px] font-bold text-white truncate" style={{ fontFamily: "var(--font-syne)" }}>
            {engineer.login}
          </div>
          <div className="text-[9px]" style={{ color: "var(--accent)", fontFamily: "var(--font-dm-mono)" }}>
            Rank #{rank} · Impact {(engineer.impactScore * 100).toFixed(1)}
          </div>
        </div>
        <button
          onClick={onClose}
          className="w-5 h-5 rounded flex items-center justify-center text-slate-500 hover:text-white hover:bg-white/5 transition-colors"
          style={{ fontSize: 11, fontFamily: "var(--font-dm-mono)" }}
        >
          ✕
        </button>
      </div>

      {/* Formula */}
      <div
        className="mx-3 mb-2 rounded-md px-2 py-1 text-[8.5px]"
        style={{ background: "rgba(255,255,255,0.02)", border: "1px solid rgba(255,255,255,0.04)", fontFamily: "var(--font-dm-mono)" }}
      >
        <span style={{ color: "#10b981" }}>{(engineer.executionQualityScore * 100).toFixed(0)}</span>
        <span style={{ color: "var(--text-muted)", opacity: 0.4 }}>×.4</span>
        <span style={{ color: "var(--text-muted)", opacity: 0.3 }}> + </span>
        <span style={{ color: "#3b82f6" }}>{(engineer.collaborationScore * 100).toFixed(0)}</span>
        <span style={{ color: "var(--text-muted)", opacity: 0.4 }}>×.3</span>
        <span style={{ color: "var(--text-muted)", opacity: 0.3 }}> + </span>
        <span style={{ color: "#a78bfa" }}>{(engineer.codeHealthScore * 100).toFixed(0)}</span>
        <span style={{ color: "var(--text-muted)", opacity: 0.4 }}>×.3</span>
        <span style={{ color: "var(--text-muted)", opacity: 0.3 }}> = </span>
        <span className="font-bold" style={{ color: "var(--accent)" }}>{(engineer.impactScore * 100).toFixed(1)}</span>
      </div>

      {/* 3 Pillars compact */}
      <div className="mx-3 mb-2 grid grid-cols-3 gap-1.5">
        <div className="rounded-md p-1.5" style={{ background: "rgba(16,185,129,0.05)" }}>
          <div className="text-[8px] uppercase tracking-wider mb-0.5" style={{ color: "#10b981", fontFamily: "var(--font-dm-mono)" }}>
            Exec {(engineer.executionQualityScore * 100).toFixed(0)}
          </div>
          {[
            { l: "Cad", v: eq.mergeCadence },
            { l: "Lead", v: eq.leadTime },
            { l: "Fail", v: eq.changeFailureRate },
            { l: "Rec", v: eq.recencyScore },
            { l: "Eff", v: eq.prEffortScore },
          ].map((m) => (
            <div key={m.l} className="flex justify-between text-[7px]" style={{ fontFamily: "var(--font-dm-mono)" }}>
              <span style={{ color: "var(--text-muted)" }}>{m.l}</span>
              <span style={{ color: "#10b981" }}>{(m.v * 100).toFixed(0)}</span>
            </div>
          ))}
        </div>
        <div className="rounded-md p-1.5" style={{ background: "rgba(59,130,246,0.05)" }}>
          <div className="text-[8px] uppercase tracking-wider mb-0.5" style={{ color: "#3b82f6", fontFamily: "var(--font-dm-mono)" }}>
            Collab {(engineer.collaborationScore * 100).toFixed(0)}
          </div>
          <div className="text-[7px]" style={{ color: "var(--text-muted)", fontFamily: "var(--font-dm-mono)" }}>
            <div>{engineer.reviewsGiven} reviews</div>
            <div>{engineer.avgCommentsPerReview.toFixed(1)} avg cmts</div>
            <div>{engineer.reviewsReceived} received</div>
          </div>
        </div>
        <div className="rounded-md p-1.5" style={{ background: "rgba(167,139,250,0.05)" }}>
          <div className="text-[8px] uppercase tracking-wider mb-0.5" style={{ color: "#a78bfa", fontFamily: "var(--font-dm-mono)" }}>
            Health {(engineer.codeHealthScore * 100).toFixed(0)}
          </div>
          <div className="text-[7px]" style={{ color: "var(--text-muted)", fontFamily: "var(--font-dm-mono)" }}>
            <div>Churn {(engineer.churnRate * 100).toFixed(0)}%</div>
            <div>Reliab {(engineer.mergeReliability * 100).toFixed(0)}%</div>
          </div>
        </div>
      </div>

      {/* Review edges */}
      {reviewsGiven.length > 0 && (
        <div className="mx-3 mb-1.5">
          <div className="text-[7px] uppercase tracking-wider mb-0.5" style={{ color: "var(--text-muted)", fontFamily: "var(--font-dm-mono)" }}>
            Reviews given (edge = reviews × depth × EQ)
          </div>
          {reviewsGiven.map((e) => (
            <div key={e.target} className="flex items-center text-[8px] py-px" style={{ fontFamily: "var(--font-dm-mono)" }}>
              <span style={{ color: "var(--text-secondary)" }}>→ {e.target}</span>
              <span className="flex-1" />
              <span className="tabular-nums" style={{ color: "var(--accent)" }}>{e.weight.toFixed(1)}</span>
            </div>
          ))}
        </div>
      )}
      {reviewsReceived.length > 0 && (
        <div className="mx-3 mb-2">
          <div className="text-[7px] uppercase tracking-wider mb-0.5" style={{ color: "var(--text-muted)", fontFamily: "var(--font-dm-mono)" }}>
            Reviews received
          </div>
          {reviewsReceived.map((e) => {
            const rev = engineerMap.get(e.source);
            return (
              <div key={e.source} className="flex items-center text-[8px] py-px" style={{ fontFamily: "var(--font-dm-mono)" }}>
